     1→import {ChainForkConfig} from "@lodestar/config";
     2→import {ForkName, isForkPostFulu} from "@lodestar/params";
     3→import {Epoch, Root, Slot, phase0} from "@lodestar/types";
     4→import {ErrorAborted, Logger, toRootHex} from "@lodestar/utils";
     5→import {BlockInput, BlockInputDataColumns, BlockInputType} from "../../chain/blocks/types.js";
     6→import {Metrics} from "../../metrics/metrics.js";
     7→import {PeerAction, prettyPrintPeerIdStr} from "../../network/index.js";
     8→import {PeerSyncMeta} from "../../network/peers/peersData.js";
     9→import {PartialDownload} from "../../network/reqresp/beaconBlocksMaybeBlobsByRange.js";
    10→import {CustodyConfig} from "../../util/dataColumns.js";
    11→import {ItTrigger} from "../../util/itTrigger.js";
    12→import {PeerIdStr} from "../../util/peerId.js";
    13→import {wrapError} from "../../util/wrapError.js";
    14→import {BATCH_BUFFER_SIZE, EPOCHS_PER_BATCH, MAX_LOOK_AHEAD_EPOCHS} from "../constants.js";
    15→import {RangeSyncType} from "../utils/remoteSyncType.js";
    16→import {Batch, BatchError, BatchErrorCode, BatchMetadata, BatchStatus} from "./batch.js";
    17→import {
    18→  ChainPeersBalancer,
    19→  PeerSyncInfo,
    20→  batchStartEpochIsAfterSlot,
    21→  computeHighestTarget,
    22→  getBatchSlotRange,
    23→  getNextBatchToProcess,
    24→  isSyncChainDone,
    25→  toArr,
    26→  toBeDownloadedStartEpoch,
    27→  validateBatchesStatus,
    28→} from "./utils/index.js";
    29→
    30→export type SyncChainModules = {
    31→  config: ChainForkConfig;
    32→  custodyConfig: CustodyConfig;
    33→  logger: Logger;
    34→  metrics: Metrics | null;
    35→};
    36→
    37→export type SyncChainFns = {
    38→  /**
    39→   * Must return if ALL blocks are processed successfully
    40→   * If SOME blocks are processed must throw BlockProcessorError()
    41→   */
    42→  processChainSegment: (blocks: BlockInput[], syncType: RangeSyncType) => Promise<void>;
    43→  /** Must download blocks, and validate their range */
    44→  downloadBeaconBlocksByRange: (
    45→    peer: PeerSyncMeta,
    46→    request: phase0.BeaconBlocksByRangeRequest,
    47→    partialDownload: PartialDownload
    48→  ) => Promise<{blocks: BlockInput[]; pendingDataColumns: null | number[]}>;
    49→  /** Report peer for negative actions. Decouples from the full network instance */
    50→  reportPeer: (peer: PeerIdStr, action: PeerAction, actionName: string) => void;
    51→  /** Gets current peer custodyColumns and earliestAvailableSlot */
    52→  getConnectedPeerSyncMeta: (peerId: string) => PeerSyncMeta;
    53→  /** Hook called when Chain state completes */
    54→  onEnd: (err: Error | null, target: ChainTarget | null) => void;
    55→};
    56→
    57→/**
    58→ * Sync this up to this target. Uses slot instead of epoch to re-use logic for finalized sync
    59→ * and head sync. The root is used to uniquely identify this chain on different forks
    60→ */
    61→export type ChainTarget = {
    62→  slot: Slot;
    63→  root: Root;
    64→};
    65→
    66→export class SyncChainStartError extends Error {}
    67→
    68→export type SyncChainDebugState = {
    69→  targetRoot: string | null;
    70→  targetSlot: number | null;
    71→  syncType: RangeSyncType;
    72→  status: SyncChainStatus;
    73→  startEpoch: number;
    74→  peers: number;
    75→  batches: BatchMetadata[];
    76→};
    77→
    78→export enum SyncChainStatus {
    79→  Stopped = "Stopped",
    80→  Syncing = "Syncing",
    81→  Done = "Done",
    82→  Error = "Error",
    83→}
    84→
    85→// this global chain id is used to identify the chain over time, increase it every time a new chain is created
    86→// a chain type could be Finalized or Head, so it should be appended with this id to make the log unique
    87→let nextChainId = 0;
    88→
    89→/**
    90→ * Dynamic target sync chain. Peers with multiple targets but with the same syncType are added
    91→ * through the `addPeer()` hook.
    92→ *
    93→ * A chain of blocks that need to be downloaded. Peers who claim to contain the target head
    94→ * root are grouped into the peer pool and queried for batches when downloading the chain.
    95→ */
    96→export class SyncChain {
    97→  /** Short string id to identify this SyncChain in logs */
    98→  readonly logId: string;
    99→  readonly syncType: RangeSyncType;
   100→  /**
   101→   * Should sync up until this slot, then stop.
   102→   * Finalized SyncChains have a dynamic target, so if this chain has no peers the target can become null
   103→   */
   104→  target: ChainTarget;
   105→
   106→  /** Number of validated epochs. For the SyncRange to prevent switching chains too fast */
   107→  validatedEpochs = 0;
   108→
   109→  readonly firstBatchEpoch: Epoch;
   110→  /**
   111→   * The start of the chain segment. Any epoch previous to this one has been validated.
   112→   * Note: lastEpochWithProcessBlocks` signals the epoch at which 1 or more blocks have been processed
   113→   * successfully. So that epoch itself may or may not be valid.
   114→   */
   115→  private lastEpochWithProcessBlocks: Epoch;
   116→  private status = SyncChainStatus.Stopped;
   117→
   118→  private readonly processChainSegment: SyncChainFns["processChainSegment"];
   119→  private readonly downloadBeaconBlocksByRange: SyncChainFns["downloadBeaconBlocksByRange"];
   120→  private readonly reportPeer: SyncChainFns["reportPeer"];
   121→  private readonly getConnectedPeerSyncMeta: SyncChainFns["getConnectedPeerSyncMeta"];
   122→  /** AsyncIterable that guarantees processChainSegment is run only at once at anytime */
   123→  private readonly batchProcessor = new ItTrigger();
   124→  /** Sorted map of batches undergoing some kind of processing. */
   125→  private readonly batches = new Map<Epoch, Batch>();
   126→  private readonly peerset = new Map<PeerIdStr, ChainTarget>();
   127→
   128→  private readonly logger: Logger;
   129→  private readonly config: ChainForkConfig;
   130→  private readonly custodyConfig: CustodyConfig;
   131→
   132→  constructor(
   133→    initialBatchEpoch: Epoch,
   134→    initialTarget: ChainTarget,
   135→    syncType: RangeSyncType,
   136→    fns: SyncChainFns,
   137→    modules: SyncChainModules
   138→  ) {
   139→    const {config, custodyConfig, logger, metrics} = modules;
   140→    this.firstBatchEpoch = initialBatchEpoch;
   141→    this.lastEpochWithProcessBlocks = initialBatchEpoch;
   142→    this.target = initialTarget;
   143→    this.syncType = syncType;
   144→    this.processChainSegment = fns.processChainSegment;
   145→    this.downloadBeaconBlocksByRange = fns.downloadBeaconBlocksByRange;
   146→    this.reportPeer = fns.reportPeer;
   147→    this.getConnectedPeerSyncMeta = fns.getConnectedPeerSyncMeta;
   148→    this.config = config;
   149→    this.custodyConfig = custodyConfig;
   150→    this.logger = logger;
   151→    this.logId = `${syncType}-${nextChainId++}`;
   152→
   153→    if (metrics) {
   154→      metrics.syncRange.headSyncPeers.addCollect(() => this.scrapeMetrics(metrics));
   155→    }
   156→
   157→    // Trigger event on parent class
   158→    this.sync().then(
   159→      () => fns.onEnd(null, this.target),
   160→      (e) => fns.onEnd(e, null)
   161→    );
   162→  }
   163→
   164→  /**
   165→   * Start syncing a new chain or an old one with an existing peer list
   166→   * In the same call, advance the chain if localFinalizedEpoch >
   167→   */
   168→  startSyncing(localFinalizedEpoch: Epoch): void {
   169→    switch (this.status) {
   170→      case SyncChainStatus.Stopped:
   171→        break; // Ok, continue
   172→      case SyncChainStatus.Syncing:
   173→        return; // Skip, already started
   174→      case SyncChainStatus.Error:
   175→      case SyncChainStatus.Done:
   176→        throw new SyncChainStartError(`Attempted to start an ended SyncChain ${this.status}`);
   177→    }
   178→
   179→    this.status = SyncChainStatus.Syncing;
   180→
   181→    this.logger.debug("SyncChain startSyncing", {
   182→      localFinalizedEpoch,
   183→      lastEpochWithProcessBlocks: this.lastEpochWithProcessBlocks,
   184→      targetSlot: this.target.slot,
   185→    });
   186→
   187→    // to avoid dropping local progress, we advance the chain with its batch boundaries.
   188→    // get the aligned epoch that produces a batch containing the `localFinalizedEpoch`
   189→    const lastEpochWithProcessBlocksAligned =
   190→      this.lastEpochWithProcessBlocks +
   191→      Math.floor((localFinalizedEpoch - this.lastEpochWithProcessBlocks) / EPOCHS_PER_BATCH) * EPOCHS_PER_BATCH;
   192→    this.advanceChain(lastEpochWithProcessBlocksAligned);
   193→
   194→    // Potentially download new batches and process pending
   195→    this.triggerBatchDownloader();
   196→    this.triggerBatchProcessor();
   197→  }
   198→
   199→  /**
   200→   * Temporarily stop the chain. Will prevent batches from being processed
   201→   */
   202→  stopSyncing(): void {
   203→    this.status = SyncChainStatus.Stopped;
   204→  }
   205→
   206→  /**
   207→   * Permanently remove this chain. Throws the main AsyncIterable
   208→   */
   209→  remove(): void {
   210→    this.batchProcessor.end(new ErrorAborted("SyncChain"));
   211→  }
   212→
   213→  /**
   214→   * Add peer to the chain and request batches if active
   215→   */
   216→  addPeer(peer: PeerIdStr, target: ChainTarget): void {
   217→    this.peerset.set(peer, target);
   218→    this.computeTarget();
   219→    this.triggerBatchDownloader();
   220→  }
   221→
   222→  /**
   223→   * Returns true if the peer existed and has been removed
   224→   * NOTE: The RangeSync will take care of deleting the SyncChain if peers = 0
   225→   */
   226→  removePeer(peerId: PeerIdStr): boolean {
   227→    const deleted = this.peerset.delete(peerId);
   228→    this.computeTarget();
   229→    return deleted;
   230→  }
   231→
   232→  /**
   233→   * Helper to print internal state for debugging when chain gets stuck
   234→   */
   235→  getBatchesState(): BatchMetadata[] {
   236→    return toArr(this.batches).map((batch) => batch.getMetadata());
   237→  }
   238→
   239→  get lastValidatedSlot(): Slot {
   240→    // Last epoch of the batch after the last one validated
   241→    return getBatchSlotRange(this.lastEpochWithProcessBlocks + EPOCHS_PER_BATCH).startSlot - 1;
   242→  }
   243→
   244→  get isSyncing(): boolean {
   245→    return this.status === SyncChainStatus.Syncing;
   246→  }
   247→
   248→  get isRemovable(): boolean {
   249→    return this.status === SyncChainStatus.Error || this.status === SyncChainStatus.Done;
   250→  }
   251→
   252→  get peers(): number {
   253→    return this.peerset.size;
   254→  }
   255→
   256→  getPeers(): PeerIdStr[] {
   257→    return Array.from(this.peerset.keys());
   258→  }
   259→
   260→  /** Full debug state for lodestar API */
   261→  getDebugState(): SyncChainDebugState {
   262→    return {
   263→      targetRoot: toRootHex(this.target.root),
   264→      targetSlot: this.target.slot,
   265→      syncType: this.syncType,
   266→      status: this.status,
   267→      startEpoch: this.lastEpochWithProcessBlocks,
   268→      peers: this.peers,
   269→      batches: this.getBatchesState(),
   270→    };
   271→  }
   272→
   273→  private computeTarget(): void {
   274→    if (this.peerset.size > 0) {
   275→      const targets = Array.from(this.peerset.values());
   276→      this.target = computeHighestTarget(targets);
   277→    }
   278→  }
   279→
   280→  /**
   281→   * Main Promise that handles the sync process. Will resolve when initial sync completes
   282→   * i.e. when it successfully processes a epoch >= than this chain `targetEpoch`
   283→   */
   284→  private async sync(): Promise<void> {
   285→    try {
   286→      // Start processing batches on demand in strict sequence
   287→      for await (const _ of this.batchProcessor) {
   288→        if (this.status !== SyncChainStatus.Syncing) {
   289→          continue;
   290→        }
   291→
   292→        // TODO: Consider running this check less often after the sync is well tested
   293→        validateBatchesStatus(toArr(this.batches));
   294→
   295→        // Returns true if SyncChain has processed all possible blocks with slot <= target.slot
   296→        if (isSyncChainDone(toArr(this.batches), this.lastEpochWithProcessBlocks, this.target.slot)) {
   297→          break;
   298→        }
   299→
   300→        // Processes the next batch if ready
   301→        const batch = getNextBatchToProcess(toArr(this.batches));
   302→        if (batch) await this.processBatch(batch);
   303→      }
   304→
   305→      this.status = SyncChainStatus.Done;
   306→      this.logger.verbose("SyncChain Done", {id: this.logId});
   307→    } catch (e) {
   308→      if (e instanceof ErrorAborted) {
   309→        return; // Ignore
   310→      }
   311→
   312→      this.status = SyncChainStatus.Error;
   313→      this.logger.verbose("SyncChain Error", {id: this.logId}, e as Error);
   314→
   315→      // If a batch exceeds it's retry limit, maybe downscore peers.
   316→      // shouldDownscoreOnBatchError() functions enforces that all BatchErrorCode values are covered
   317→      if (e instanceof BatchError) {
   318→        const shouldReportPeer = shouldReportPeerOnBatchError(e.type.code);
   319→        if (shouldReportPeer) {
   320→          for (const peer of this.peerset.keys()) {
   321→            this.reportPeer(peer, shouldReportPeer.action, shouldReportPeer.reason);
   322→          }
   323→        }
   324→      }
   325→
   326→      throw e;
   327→    }
   328→  }
   329→
   330→  /**
   331→   * Request to process batches if possible
   332→   */
   333→  private triggerBatchProcessor(): void {
   334→    this.batchProcessor.trigger();
   335→  }
   336→
   337→  /**
   338→   * Request to download batches if possible
   339→   * Backlogs requests into a single pending request
   340→   */
   341→  private triggerBatchDownloader(): void {
   342→    try {
   343→      this.requestBatches();
   344→    } catch (e) {
   345→      // bubble the error up to the main async iterable loop
   346→      this.batchProcessor.end(e as Error);
   347→    }
   348→  }
   349→
   350→  /**
   351→   * Attempts to request the next required batches from the peer pool if the chain is syncing.
   352→   * It will exhaust the peer pool and left over batches until the batch buffer is reached.
   353→   */
   354→  private requestBatches(): void {
   355→    if (this.status !== SyncChainStatus.Syncing) {
   356→      return;
   357→    }
   358→
   359→    const peersSyncInfo: PeerSyncInfo[] = [];
   360→    for (const [peerId, target] of this.peerset.entries()) {
   361→      try {
   362→        peersSyncInfo.push({...this.getConnectedPeerSyncMeta(peerId), target});
   363→      } catch (e) {
   364→        this.logger.debug("Failed to get peer sync meta", {peerId}, e as Error);
   365→      }
   366→    }
   367→
   368→    const peerBalancer = new ChainPeersBalancer(peersSyncInfo, toArr(this.batches), this.custodyConfig);
   369→
   370→    // Retry download of existing batches
   371→    for (const batch of this.batches.values()) {
   372→      if (batch.state.status !== BatchStatus.AwaitingDownload) {
   373→        continue;
   374→      }
   375→
   376→      const peer = peerBalancer.bestPeerToRetryBatch(batch);
   377→      if (peer) {
   378→        void this.sendBatch(batch, peer);
   379→      }
   380→    }
   381→
   382→    // find the next pending batch and request it from the peer
   383→    let batch = this.includeNextBatch();
   384→    while (batch != null) {
   385→      const peer = peerBalancer.idlePeerForBatch(batch);
   386→      if (!peer) {
   387→        // if there is no peer available, we stop requesting batches because next batches will have greater startEpoch with the same sampling groups
   388→        break;
   389→      }
   390→      void this.sendBatch(batch, peer);
   391→      batch = this.includeNextBatch();
   392→    }
   393→  }
   394→
   395→  /**
   396→   * Creates the next required batch from the chain. If there are no more batches required, returns `null`.
   397→   */
   398→  private includeNextBatch(): Batch | null {
   399→    const batches = toArr(this.batches);
   400→
   401→    // Only request batches up to the buffer size limit
   402→    // Note: Don't count batches in the AwaitingValidation state, to prevent stalling sync
   403→    // if the current processing window is contained in a long range of skip slots.
   404→    const batchesInBuffer = batches.filter((batch) => {
   405→      return batch.state.status === BatchStatus.Downloading || batch.state.status === BatchStatus.AwaitingProcessing;
   406→    });
   407→    if (batchesInBuffer.length > BATCH_BUFFER_SIZE) {
   408→      return null;
   409→    }
   410→
   411→    // if last processed epoch is n, we don't want to request batches with epoch > n + MAX_LOOK_AHEAD_EPOCHS
   412→    // we should have enough batches to process in the buffer: n + 1, ..., n + MAX_LOOK_AHEAD_EPOCHS
   413→    // let's focus on redownloading these batches first because it may have to reach different peers to get enough sampled columns
   414→    if (
   415→      batches.length > 0 &&
   416→      Math.max(...batches.map((b) => b.startEpoch)) >= this.lastEpochWithProcessBlocks + MAX_LOOK_AHEAD_EPOCHS
   417→    ) {
   418→      return null;
   419→    }
   420→
   421→    // This line decides the starting epoch of the next batch. MUST ensure no duplicate batch for the same startEpoch
   422→    const startEpoch = toBeDownloadedStartEpoch(batches, this.lastEpochWithProcessBlocks);
   423→
   424→    // Don't request batches beyond the target head slot. The to-be-downloaded batch must be strictly after target.slot
   425→    if (batchStartEpochIsAfterSlot(startEpoch, this.target.slot)) {
   426→      return null;
   427→    }
   428→
   429→    if (this.batches.has(startEpoch)) {
   430→      this.logger.error("Attempting to add existing Batch to SyncChain", {id: this.logId, startEpoch});
   431→      return null;
   432→    }
   433→
   434→    const batch = new Batch(startEpoch, this.config);
   435→    this.batches.set(startEpoch, batch);
   436→    return batch;
   437→  }
   438→
   439→  /**
   440→   * Requests the batch assigned to the given id from a given peer.
   441→   */
   442→  private async sendBatch(batch: Batch, peer: PeerSyncMeta): Promise<void> {
   443→    this.logger.verbose("Downloading batch", {
   444→      id: this.logId,
   445→      ...batch.getMetadata(),
   446→      peer: prettyPrintPeerIdStr(peer.peerId),
   447→    });
   448→    try {
   449→      const partialDownload = batch.startDownloading(peer.peerId);
   450→
   451→      // wrapError ensures to never call both batch success() and batch error()
   452→      const res = await wrapError(this.downloadBeaconBlocksByRange(peer, batch.request, partialDownload));
   453→
   454→      if (!res.err) {
   455→        const downloadSuccessOutput = batch.downloadingSuccess(res.result);
   456→        if (downloadSuccessOutput.status === BatchStatus.AwaitingProcessing) {
   457→          const blocks = downloadSuccessOutput.blocks;
   458→          let hasPostDenebBlocks = false;
   459→          const blobs = blocks.reduce((acc, blockInput) => {
   460→            hasPostDenebBlocks ||= blockInput.type === BlockInputType.availableData;
   461→            return hasPostDenebBlocks
   462→              ? acc +
   463→                  (blockInput.type === BlockInputType.availableData &&
   464→                  (blockInput.blockData.fork === ForkName.deneb || blockInput.blockData.fork === ForkName.electra)
   465→                    ? blockInput.blockData.blobs.length
   466→                    : 0)
   467→              : 0;
   468→          }, 0);
   469→          const dataColumns = blocks.reduce((acc, blockInput) => {
   470→            hasPostDenebBlocks ||= blockInput.type === BlockInputType.availableData;
   471→            return hasPostDenebBlocks
   472→              ? acc +
   473→                  (blockInput.type === BlockInputType.availableData && isForkPostFulu(blockInput.blockData.fork)
   474→                    ? (blockInput.blockData as BlockInputDataColumns).dataColumns.length
   475→                    : 0)
   476→              : 0;
   477→          }, 0);
   478→
   479→          const downloadInfo = {blocks: blocks.length};
   480→          if (hasPostDenebBlocks) {
   481→            Object.assign(downloadInfo, {blobs, dataColumns});
   482→          }
   483→          this.logger.debug("Downloaded batch", {
   484→            id: this.logId,
   485→            ...batch.getMetadata(),
   486→            ...downloadInfo,
   487→            peer: prettyPrintPeerIdStr(peer.peerId),
   488→          });
   489→          this.triggerBatchProcessor();
   490→        } else {
   491→          const pendingDataColumns = downloadSuccessOutput.pendingDataColumns.join(",");
   492→          this.logger.debug("Partially downloaded batch", {
   493→            id: this.logId,
   494→            ...batch.getMetadata(),
   495→            pendingDataColumns,
   496→            peer: peer.peerId,
   497→          });
   498→          // the flow will continue to call triggerBatchDownloader() below
   499→        }
   500→      } else {
   501→        this.logger.verbose(
   502→          "Batch download error",
   503→          {id: this.logId, ...batch.getMetadata(), peer: prettyPrintPeerIdStr(peer.peerId)},
   504→          res.err
   505→        );
   506→        batch.downloadingError(); // Throws after MAX_DOWNLOAD_ATTEMPTS
   507→      }
   508→
   509→      // Preemptively request more blocks from peers whilst we process current blocks
   510→      this.triggerBatchDownloader();
   511→    } catch (e) {
   512→      // bubble the error up to the main async iterable loop
   513→      this.batchProcessor.end(e as Error);
   514→    }
   515→
   516→    // Preemptively request more blocks from peers whilst we process current blocks
   517→    this.triggerBatchDownloader();
   518→  }
   519→
   520→  /**
   521→   * Sends `batch` to the processor. Note: batch may be empty
   522→   */
   523→  private async processBatch(batch: Batch): Promise<void> {
   524→    const blocks = batch.startProcessing();
   525→
   526→    // wrapError ensures to never call both batch success() and batch error()
   527→    const res = await wrapError(this.processChainSegment(blocks, this.syncType));
   528→
   529→    if (!res.err) {
   530→      batch.processingSuccess();
   531→
   532→      // If the processed batch is not empty, validate previous AwaitingValidation blocks.
   533→      if (blocks.length > 0) {
   534→        this.advanceChain(batch.startEpoch);
   535→      }
   536→
   537→      // Potentially process next AwaitingProcessing batch
   538→      this.triggerBatchProcessor();
   539→    } else {
   540→      this.logger.verbose("Batch process error", {id: this.logId, ...batch.getMetadata()}, res.err);
   541→      batch.processingError(res.err); // Throws after MAX_BATCH_PROCESSING_ATTEMPTS
   542→
   543→      // At least one block was successfully verified and imported, so we can be sure all
   544→      // previous batches are valid and we only need to download the current failed batch.
   545→      // TODO: Disabled for now
   546→      // if (res.err instanceof ChainSegmentError && res.err.importedBlocks > 0) {
   547→      //   this.advanceChain(batch.startEpoch);
   548→      // }
   549→
   550→      // The current batch could not be processed, so either this or previous batches are invalid.
   551→      // All previous batches (AwaitingValidation) are potentially faulty and marked for retry.
   552→      // Progress will be drop back to `this.startEpoch`
   553→      for (const pendingBatch of this.batches.values()) {
   554→        if (pendingBatch.startEpoch < batch.startEpoch) {
   555→          this.logger.verbose("Batch validation error", {id: this.logId, ...pendingBatch.getMetadata()});
   556→          pendingBatch.validationError(res.err); // Throws after MAX_BATCH_PROCESSING_ATTEMPTS
   557→        }
   558→      }
   559→    }
   560→
   561→    // A batch is no longer in Processing status, queue has an empty spot to download next batch
   562→    this.triggerBatchDownloader();
   563→  }
   564→
   565→  /**
   566→   * Drops any batches previous to `newLatestValidatedEpoch` and updates the chain boundaries
   567→   */
   568→  private advanceChain(newLastEpochWithProcessBlocks: Epoch): void {
   569→    // make sure this epoch produces an advancement
   570→    if (newLastEpochWithProcessBlocks <= this.lastEpochWithProcessBlocks) {
   571→      return;
   572→    }
   573→
   574→    for (const [batchKey, batch] of this.batches.entries()) {
   575→      if (batch.startEpoch < newLastEpochWithProcessBlocks) {
   576→        this.batches.delete(batchKey);
   577→        this.validatedEpochs += EPOCHS_PER_BATCH;
   578→
   579→        // The last batch attempt is right, all others are wrong. Penalize other peers
   580→        const attemptOk = batch.validationSuccess();
   581→        for (const attempt of batch.failedProcessingAttempts) {
   582→          if (attempt.hash !== attemptOk.hash) {
   583→            if (attemptOk.peer === attempt.peer.toString()) {
   584→              // The same peer corrected its previous attempt
   585→              this.reportPeer(attempt.peer, PeerAction.MidToleranceError, "SyncChainInvalidBatchSelf");
   586→            } else {
   587→              // A different peer sent an bad batch
   588→              this.reportPeer(attempt.peer, PeerAction.LowToleranceError, "SyncChainInvalidBatchOther");
   589→            }
   590→          }
   591→        }
   592→      }
   593→    }
   594→
   595→    this.lastEpochWithProcessBlocks = newLastEpochWithProcessBlocks;
   596→    this.logger.verbose("Advanced chain", {
   597→      id: this.logId,
   598→      lastEpochWithProcessBlocks: this.lastEpochWithProcessBlocks,
   599→    });
   600→  }
   601→
   602→  private scrapeMetrics(metrics: Metrics): void {
   603→    const syncPeersMetric =
   604→      this.syncType === RangeSyncType.Finalized
   605→        ? metrics.syncRange.finalizedSyncPeers
   606→        : metrics.syncRange.headSyncPeers;
   607→
   608→    const peersSyncMeta = new Map<PeerIdStr, PeerSyncMeta>();
   609→    for (const peerId of this.peerset.keys()) {
   610      try {
   611→        peersSyncMeta.set(peerId, this.getConnectedPeerSyncMeta(peerId));
   612→      } catch (_) {
   613→        // ignore for metric as peer could be disconnected
   614→      }
   615→    }
   616→
   617→    const peersByColumnIndex = new Map<number, number>();
   618→    for (const [columnIndex, column] of this.custodyConfig.sampledColumns.entries()) {
   619→      for (const {custodyGroups} of peersSyncMeta.values()) {
   620→        if (custodyGroups.includes(column)) {
   621→          peersByColumnIndex.set(columnIndex, (peersByColumnIndex.get(columnIndex) ?? 0) + 1);
   622→        }
   623→      }
   624→    }
   625→
   626→    for (let columnIndex = 0; columnIndex < this.custodyConfig.sampledColumns.length; columnIndex++) {
   627→      const peerCount = peersByColumnIndex.get(columnIndex) ?? 0;
   628→      syncPeersMetric.set({columnIndex}, peerCount);
   629→    }
   630→  }
   631→}
   632→
   633→/**
   634→ * Enforces that a report peer action is defined for all BatchErrorCode exhaustively.
   635→ * If peer should not be downscored, returns null.
   636→ */
   637→export function shouldReportPeerOnBatchError(
   638→  code: BatchErrorCode
   639→): {action: PeerAction.LowToleranceError; reason: string} | null {
   640→  switch (code) {
   641→    // A batch could not be processed after max retry limit. It's likely that all peers
   642→    // in this chain are sending invalid batches repeatedly so are either malicious or faulty.
   643→    // We drop the chain and report all peers.
   644→    // There are some edge cases with forks that could cause this situation, but it's unlikely.
   645→    case BatchErrorCode.MAX_PROCESSING_ATTEMPTS:
   646→      return {action: PeerAction.LowToleranceError, reason: "SyncChainMaxProcessingAttempts"};
   647→
   648→    // TODO: Should peers be reported for MAX_DOWNLOAD_ATTEMPTS?
   649→    case BatchErrorCode.WRONG_STATUS:
   650→    case BatchErrorCode.MAX_DOWNLOAD_ATTEMPTS:
   651→    case BatchErrorCode.MAX_EXECUTION_ENGINE_ERROR_ATTEMPTS:
   652→      return null;
   653→  }
   654→}
   655→

