    31→import {INetwork} from "../interface.js";
    32→import {PartialDownload, matchBlockWithBlobs, matchBlockWithDataColumns} from "./beaconBlocksMaybeBlobsByRange.js";
    33→
    34→// keep 1 epoch of stuff, assmume 16 blobs
    35→const MAX_ENGINE_GETBLOBS_CACHE = 32 * 16;
    36→const MAX_UNAVAILABLE_RETRY_CACHE = 32;
    37→
    38→export async function beaconBlocksMaybeBlobsByRoot(
    39→  config: ChainForkConfig,
    40→  network: INetwork,
    41→  peerId: PeerIdStr,
    42→  request: phase0.BeaconBlocksByRootRequest,
    43→  partialDownload: null | PartialDownload,
    44→  peerClient: string,
    45→  metrics: Metrics | null,
    46→  logger?: Logger
    47→): Promise<{blocks: BlockInput[]; pendingDataColumns: null | number[]}> {
    48→  // console.log("beaconBlocksMaybeBlobsByRoot", request);
    49→  const allBlocks = partialDownload
    50→    ? partialDownload.blocks.map((blockInput) => ({data: blockInput.block}))
    51→    : await network.sendBeaconBlocksByRoot(peerId, request);
    52→
    53→  logger?.debug("beaconBlocksMaybeBlobsByRoot response", {allBlocks: allBlocks.length, peerClient});
    54→
    55→  const preDataBlocks = [];
    56→  const blobsDataBlocks = [];
    57→  const dataColumnsDataBlocks = [];
    58→
    59→  const sampledColumns = network.custodyConfig.sampledColumns;
    60→  const neededColumns = partialDownload ? partialDownload.pendingDataColumns : sampledColumns;
    61→  const {custodyGroups: peerColumns} = network.getConnectedPeerSyncMeta(peerId);
    62→
    63→  // get match
    64→  const columns = peerColumns.reduce((acc, elem) => {
    65→    if (neededColumns.includes(elem)) {
    66→      acc.push(elem);
    67→    }
    68→    return acc;
    69→  }, [] as number[]);
    70→  let pendingDataColumns = null;
    71→
    72→  const blobIdentifiers: deneb.BlobIdentifier[] = [];
    73→  const dataColumnsByRootIdentifiers: fulu.DataColumnsByRootIdentifier[] = [];
    74→
    75→  let prevFork = null;
    76→  for (const block of allBlocks) {
    77→    const slot = block.data.message.slot;
    78→    const blockRoot = config.getForkTypes(slot).BeaconBlock.hashTreeRoot(block.data.message);
    79→    const fork = config.getForkName(slot);
    80→    if (fork !== (prevFork ?? fork)) {
    81→      throw Error("beaconBlocksMaybeBlobsByRoot only accepts requests of same fork");
    82→    }
    83→    prevFork = fork;
    84→
    85→    if (ForkSeq[fork] < ForkSeq.deneb) {
    86→      preDataBlocks.push(block);
    87→    } else if (fork === ForkName.deneb || fork === ForkName.electra) {
    88→      blobsDataBlocks.push(block);
    89→      const blobKzgCommitmentsLen = (block.data.message.body as deneb.BeaconBlockBody).blobKzgCommitments.length;
    90→      logger?.debug("beaconBlocksMaybeBlobsByRoot", {blobKzgCommitmentsLen, peerClient});
    91→      for (let index = 0; index < blobKzgCommitmentsLen; index++) {
    92→        // try see if the blob is available locally
    93→        blobIdentifiers.push({blockRoot, index});
    94→      }
    95→    } else if (fork === ForkName.fulu) {
    96→      dataColumnsDataBlocks.push(block);
    97→      const blobKzgCommitmentsLen = (block.data.message.body as deneb.BeaconBlockBody).blobKzgCommitments.length;
    98→      const custodyColumnIndexes = blobKzgCommitmentsLen > 0 ? columns : [];
    99→      if (custodyColumnIndexes.length > 0) {
   100→        dataColumnsByRootIdentifiers.push({
   101→          blockRoot,
   102→          columns: custodyColumnIndexes,
   103→        });
   104→      }
   105→    } else {
   106→      throw Error(`Invalid fork=${fork} in beaconBlocksMaybeBlobsByRoot`);
   107→    }
   108→  }
   109→
   110→  let blockInputs = preDataBlocks.map((block) => getBlockInput.preData(config, block.data, BlockSource.byRoot));
   111→
   112→  if (blobsDataBlocks.length > 0) {
   113→    let allBlobSidecars: deneb.BlobSidecar[];
   114→    if (blobIdentifiers.length > 0) {
   115→      allBlobSidecars = await network.sendBlobSidecarsByRoot(peerId, blobIdentifiers);
   116→    } else {
   117→      allBlobSidecars = [];
   118→    }
   119→
   120→    // The last arg is to provide slot to which all blobs should be exausted in matching
   121→    // and here it should be infinity since all bobs should match
   122→    const blockInputWithBlobs = matchBlockWithBlobs(
   123→      config,
   124→      allBlocks,
   125→      allBlobSidecars,
   126→      Infinity,
   127→      BlockSource.byRoot,
   128→      BlobsSource.byRoot
   129→    );
   130→    blockInputs = [...blockInputs, ...blockInputWithBlobs];
   131→  }
   132→
   133→  if (dataColumnsDataBlocks.length > 0) {
   134→    pendingDataColumns = neededColumns.reduce((acc, elem) => {
   135→      if (!columns.includes(elem)) {
   136→        acc.push(elem);
   137→      }
   138→      return acc;
   139→    }, [] as number[]);
   140→
   141→    let allDataColumnsSidecars: fulu.DataColumnSidecar[];
   142→    logger?.debug("allDataColumnsSidecars partialDownload", {
   143→      ...(partialDownload
   144→        ? {blocks: partialDownload.blocks.length, pendingDataColumns: partialDownload.pendingDataColumns.join(" ")}
   145→        : {blocks: null, pendingDataColumns: null}),
   146→      dataColumnIdentifiers: dataColumnsByRootIdentifiers
   147→        .map((id) => `${id.blockRoot}: ${id.columns.join(" ")}`)
   148→        .join(" "),
   149→      peerClient,
   150→    });
   151→    if (dataColumnsByRootIdentifiers.length > 0) {
   152→      allDataColumnsSidecars = await network.sendDataColumnSidecarsByRoot(peerId, dataColumnsByRootIdentifiers);
   153→    } else {
   154→      if (partialDownload !== null) {
   155→        return partialDownload;
   156→      }
   157→      allDataColumnsSidecars = [];
   158→    }
   159→
   160→    // The last arg is to provide slot to which all blobs should be exausted in matching
   161→    // and here it should be infinity since all bobs should match
   162→    // TODO: should not call matchBlockWithDataColumns() because it's supposed for range sync
   163→    // in that function, peers should return all requested data columns, this function runs at gossip time
   164→    // and it should not expect that
   165→    const blockInputWithBlobs = matchBlockWithDataColumns(
   166→      network,
   167→      peerId,
   168→      config,
   169→      sampledColumns,
   170→      columns,
   171→      allBlocks,
   172→      allDataColumnsSidecars,
   173→      Infinity,
   174→      BlockSource.byRoot,
   175→      DataColumnsSource.byRoot,
   176→      partialDownload,
   177→      peerClient,
   178→      metrics,
   179→      logger
   180→    );
   181→    blockInputs = [...blockInputs, ...blockInputWithBlobs];
   182→  }
   183→
   184→  return {
   185→    blocks: blockInputs,
   186→    pendingDataColumns: pendingDataColumns && pendingDataColumns.length > 0 ? pendingDataColumns : null,
   187→  };
   188→}
   189→
   190→export async function unavailableBeaconBlobsByRoot(
   191→  config: ChainForkConfig,
   192→  network: INetwork,
   193→  peerId: PeerIdStr,
   194→  peerClient: string,
   195→  unavailableBlockInput: BlockInput | NullBlockInput,
   196→  opts: {
   197→    logger?: Logger;
   198→    metrics?: Metrics | null;
   199→    executionEngine: IExecutionEngine;
   200→    emitter: ChainEventEmitter;
   201→    engineGetBlobsCache?: Map<RootHex, BlobAndProof | null>;
   202→    blockInputsRetryTrackerCache?: Set<RootHex>;
   203→  }
   204→): Promise<BlockInput> {
   205→  if (unavailableBlockInput.block !== null && unavailableBlockInput.type !== BlockInputType.dataPromise) {
   206→    return unavailableBlockInput;
   207→  }
   208→
   209→  // resolve the block if thats unavailable
   210→  let block: SignedBeaconBlock, cachedData: NullBlockInput["cachedData"];
   211→  if (unavailableBlockInput.block === null) {
   212→    const allBlocks = await network.sendBeaconBlocksByRoot(peerId, [fromHex(unavailableBlockInput.blockRootHex)]);
   213→    block = allBlocks[0].data;
   214→    cachedData = unavailableBlockInput.cachedData;
   215→    unavailableBlockInput = getBlockInput.dataPromise(config, block, BlockSource.byRoot, cachedData);
   216→    // console.log(
   217→    //   "downloaded sendBeaconBlocksByRoot",
   218→    //   ssz.fulu.SignedBeaconBlock.toJson(block as fulu.SignedBeaconBlock)
   219→    // );
   220→  } else {
   221→    ({block, cachedData} = unavailableBlockInput);
   222→  }
   223→
   224→  const forkSeq = config.getForkSeq(block.message.slot);
   225→
   226→  if (forkSeq < ForkSeq.fulu) {
   227→    return unavailableBeaconBlobsByRootPreFulu(
   228→      config,
   229→      network,
   230→      peerId,
   231→      unavailableBlockInput,
   232→      block,
   233→      cachedData as CachedBlobs,
   234→      opts
   235→    );
   236→  }
   237→
   238→  return unavailableBeaconBlobsByRootPostFulu(
   239→    config,
   240→    network,
   241→    peerId,
   242→    peerClient,
   243→    unavailableBlockInput,
   244→    block,
   245→    cachedData,
   246→    {
   247→      metrics: opts.metrics,
   248→      executionEngine: opts.executionEngine,
   249→      emitter: opts.emitter,
   250→      logger: opts.logger,
   251→    }
   252→  );
   253→}
   254→
   255→export async function unavailableBeaconBlobsByRootPreFulu(
   256→  config: ChainForkConfig,
   257→  network: INetwork,
   258→  peerId: PeerIdStr,
   259→  unavailableBlockInput: BlockInput | NullBlockInput,
   260→  block: SignedBeaconBlock,
   261→  cachedData: CachedBlobs,
   262→  opts: {
   263→    metrics?: Metrics | null;
   264→    emitter: ChainEventEmitter;
   265→    executionEngine: IExecutionEngine;
   266→    engineGetBlobsCache?: Map<RootHex, BlobAndProof | null>;
   267→    blockInputsRetryTrackerCache?: Set<RootHex>;
   268→  }
   269→): Promise<BlockInput> {
   270→  const {executionEngine, metrics, emitter, engineGetBlobsCache, blockInputsRetryTrackerCache} = opts;
   271→  if (unavailableBlockInput.block !== null && unavailableBlockInput.type !== BlockInputType.dataPromise) {
   272→    return unavailableBlockInput;
   273→  }
   274→
   275→  // resolve missing blobs
   276→  const slot = block.message.slot;
   277→  const fork = config.getForkName(slot);
   278→  const blockRoot = config.getForkTypes(slot).BeaconBlock.hashTreeRoot(block.message);
   279→  const blockRootHex = toHexString(blockRoot);
   280→
   281→  const blockTriedBefore = blockInputsRetryTrackerCache?.has(blockRootHex) === true;
   282→  if (blockTriedBefore) {
   283→    metrics?.blockInputFetchStats.totalDataPromiseBlockInputsReTriedBlobsPull.inc();
   284→  } else {
   285→    metrics?.blockInputFetchStats.totalDataPromiseBlockInputsTriedBlobsPull.inc();
   286→    blockInputsRetryTrackerCache?.add(blockRootHex);
   287→  }
   288→
   289→  const blobKzgCommitmentsLen = (block.message.body as deneb.BeaconBlockBody).blobKzgCommitments.length;
   290→  const signedBlockHeader = signedBlockToSignedHeader(config, block);
   291→
   292→  const engineReqIdentifiers: (deneb.BlobIdentifier & {
   293→    kzgCommitment: deneb.KZGCommitment;
   294→    versionedHash: Uint8Array;
   295→  })[] = [];
   296→  const networkReqIdentifiers: deneb.BlobIdentifier[] = [];
   297→
   298→  let getBlobsUseful = false;
   299→  for (let index = 0; index < blobKzgCommitmentsLen; index++) {
   300→    if (cachedData.blobsCache.has(index) === false) {
   301→      const kzgCommitment = (block.message.body as deneb.BeaconBlockBody).blobKzgCommitments[index];
   302→      const versionedHash = kzgCommitmentToVersionedHash(kzgCommitment);
   303→
   304→      // check if the getblobs cache has the data if block not been queried before
   305→      if (engineGetBlobsCache?.has(toHexString(versionedHash)) === true && !blockTriedBefore) {
   306→        const catchedBlobAndProof = engineGetBlobsCache.get(toHexString(versionedHash)) ?? null;
   307→        if (catchedBlobAndProof === null) {
   308→          metrics?.blockInputFetchStats.dataPromiseBlobsFoundInGetBlobsCacheNull.inc();
   309→          networkReqIdentifiers.push({blockRoot, index});
   310→        } else {
   311→          metrics?.blockInputFetchStats.dataPromiseBlobsFoundInGetBlobsCacheNotNull.inc();
   312→          // compute TODO: also add inclusion proof cache
   313→          const {blob, proof: kzgProof} = catchedBlobAndProof;
   314→          const kzgCommitmentInclusionProof = computeInclusionProof(fork, block.message.body, index);
   315→          const blobSidecar = {index, blob, kzgCommitment, kzgProof, signedBlockHeader, kzgCommitmentInclusionProof};
   316→          cachedData.blobsCache.set(blobSidecar.index, blobSidecar);
   317→        }
   318→      } else if (blockTriedBefore) {
   319→        // only retry it from network
   320→        networkReqIdentifiers.push({blockRoot, index});
   321→      } else {
   322→        // see if we can pull from EL
   323→        metrics?.blockInputFetchStats.dataPromiseBlobsNotAvailableInGetBlobsCache.inc();
   324→        engineReqIdentifiers.push({blockRoot, index, versionedHash, kzgCommitment});
   325→      }
   326→    } else {
   327→      metrics?.blockInputFetchStats.dataPromiseBlobsAlreadyAvailable.inc();
   328→    }
   329→  }
   330→
   331→  if (engineReqIdentifiers.length > 0) {
   332→    metrics?.blockInputFetchStats.totalDataPromiseBlockInputsTriedGetBlobs.inc();
   333→  }
   334→  const versionedHashes = engineReqIdentifiers.map((bi) => bi.versionedHash);
   335→  metrics?.blockInputFetchStats.dataPromiseBlobsEngineGetBlobsApiRequests.inc(versionedHashes.length);
   336→
   337→  const blobAndProofs = await executionEngine.getBlobs(ForkName.deneb, versionedHashes).catch((_e) => {
   338→    metrics?.blockInputFetchStats.dataPromiseBlobsEngineApiGetBlobsErroredNull.inc(versionedHashes.length);
   339→    return versionedHashes.map((_vh) => null);
   340→  });
   341→
   342→  for (let j = 0; j < versionedHashes.length; j++) {
   343→    const blobAndProof = blobAndProofs[j] ?? null;
   344→    const versionedHash = versionedHashes[j];
   345→    // save to cache for future reference
   346→    engineGetBlobsCache?.set(toHexString(versionedHash), blobAndProof);
   347→    if (blobAndProof !== null) {
   348→      metrics?.blockInputFetchStats.dataPromiseBlobsEngineGetBlobsApiNotNull.inc();
   349→
   350→      // if we already got it by now, save the compute
   351→      if (cachedData.blobsCache.has(engineReqIdentifiers[j].index) === false) {
   352→        metrics?.blockInputFetchStats.dataPromiseBlobsEngineApiGetBlobsUseful.inc();
   353→        getBlobsUseful = true;
   354→        const {blob, proof: kzgProof} = blobAndProof;
   355→        const {kzgCommitment, index} = engineReqIdentifiers[j];
   356→        const kzgCommitmentInclusionProof = computeInclusionProof(fork, block.message.body, index);
   357→        const blobSidecar = {index, blob, kzgCommitment, kzgProof, signedBlockHeader, kzgCommitmentInclusionProof};
   358→        // add them in cache so that its reflected in all the blockInputs that carry this
   359→        // for e.g. a blockInput that might be awaiting blobs promise fullfillment in
   360→        // verifyBlocksDataAvailability
   361→        cachedData.blobsCache.set(blobSidecar.index, blobSidecar);
   362→
   363→        if (emitter.listenerCount(routes.events.EventType.blobSidecar)) {
   364→          emitter.emit(routes.events.EventType.blobSidecar, {
   365→            blockRoot: blockRootHex,
   366→            slot,
   367→            index,
   368→            kzgCommitment: toHex(kzgCommitment),
   369→            versionedHash: toHex(versionedHash),
   370→          });
   371→        }
   372→      } else {
   373→        metrics?.blockInputFetchStats.dataPromiseBlobsDelayedGossipAvailable.inc();
   374→        metrics?.blockInputFetchStats.dataPromiseBlobsDelayedGossipAvailableSavedGetBlobsCompute.inc();
   375→      }
   376→    }
   377→    // may be blobsidecar arrived in the timespan of making the request
   378→    else {
   379→      metrics?.blockInputFetchStats.dataPromiseBlobsEngineGetBlobsApiNull.inc();
   380→      if (cachedData.blobsCache.has(engineReqIdentifiers[j].index) === false) {
   381→        const {blockRoot, index} = engineReqIdentifiers[j];
   382→        networkReqIdentifiers.push({blockRoot, index});
   383→      } else {
   384→        metrics?.blockInputFetchStats.dataPromiseBlobsDelayedGossipAvailable.inc();
   385→      }
   386→    }
   387→  }
   388→
   389→  if (engineGetBlobsCache !== undefined) {
   390→    // prune out engineGetBlobsCache
   391→    let pruneLength = Math.max(0, engineGetBlobsCache?.size - MAX_ENGINE_GETBLOBS_CACHE);
   392→    for (const key of engineGetBlobsCache.keys()) {
   393→      if (pruneLength <= 0) break;
   394→      engineGetBlobsCache.delete(key);
   395→      pruneLength--;
   396→      metrics?.blockInputFetchStats.getBlobsCachePruned.inc();
   397→    }
   398→    metrics?.blockInputFetchStats.getBlobsCacheSize.set(engineGetBlobsCache.size);
   399→  }
   400→  if (blockInputsRetryTrackerCache !== undefined) {
   401→    // prune out engineGetBlobsCache
   402→    let pruneLength = Math.max(0, blockInputsRetryTrackerCache?.size - MAX_UNAVAILABLE_RETRY_CACHE);
   403→    for (const key of blockInputsRetryTrackerCache.keys()) {
   404→      if (pruneLength <= 0) break;
   405→      blockInputsRetryTrackerCache.delete(key);
   406→      pruneLength--;
   407→      metrics?.blockInputFetchStats.dataPromiseBlockInputRetryTrackerCachePruned.inc();
   408→    }
   409→    metrics?.blockInputFetchStats.dataPromiseBlockInputRetryTrackerCacheSize.set(blockInputsRetryTrackerCache.size);
   410→  }
   411→
   412→  // if clients expect sorted identifiers
   413→  networkReqIdentifiers.sort((a, b) => a.index - b.index);
   414→  let networkResBlobSidecars: deneb.BlobSidecar[];
   415→  metrics?.blockInputFetchStats.dataPromiseBlobsFinallyQueriedFromNetwork.inc(networkReqIdentifiers.length);
   416→  if (blockTriedBefore) {
   417→    metrics?.blockInputFetchStats.dataPromiseBlobsRetriedFromNetwork.inc(networkReqIdentifiers.length);
   418→  }
   419→
   420→  if (networkReqIdentifiers.length > 0) {
   421→    networkResBlobSidecars = await network.sendBlobSidecarsByRoot(peerId, networkReqIdentifiers);
   422→    metrics?.blockInputFetchStats.dataPromiseBlobsFinallyAvailableFromNetwork.inc(networkResBlobSidecars.length);
   423→    if (blockTriedBefore) {
   424→      metrics?.blockInputFetchStats.dataPromiseBlobsRetriedAvailableFromNetwork.inc(networkResBlobSidecars.length);
   425→    }
   426→  } else {
   427→    networkResBlobSidecars = [];
   428→  }
   429→
   430→  // add them in cache so that its reflected in all the blockInputs that carry this
   431→  // for e.g. a blockInput that might be awaiting blobs promise fullfillment in
   432→  // verifyBlocksDataAvailability
   433→  for (const blobSidecar of networkResBlobSidecars) {
   434→    cachedData.blobsCache.set(blobSidecar.index, blobSidecar);
   435→
   436→    if (emitter.listenerCount(routes.events.EventType.blobSidecar)) {
   437→      emitter.emit(routes.events.EventType.blobSidecar, {
   438→        blockRoot: blockRootHex,
   439→        slot,
   440→        index: blobSidecar.index,
   441→        kzgCommitment: toHex(blobSidecar.kzgCommitment),
   442→        versionedHash: toHex(kzgCommitmentToVersionedHash(blobSidecar.kzgCommitment)),
   443→      });
   444→    }
   445→  }
   446→
   447→  // check and see if all blobs are now available and in that case resolve availability
   448→  // if not this will error and the leftover blobs will be tried from another peer
   449→  const allBlobs = getBlockInputBlobs(cachedData.blobsCache);
   450→  const {blobs} = allBlobs;
   451→  if (blobs.length !== blobKzgCommitmentsLen) {
   452→    throw Error(`Not all blobs fetched missingBlobs=${blobKzgCommitmentsLen - blobs.length}`);
   453→  }
   454→  const blockData = {fork: cachedData.fork, ...allBlobs, blobsSource: BlobsSource.byRoot} as BlockInputBlobs;
   455→  cachedData.resolveAvailability(blockData);
   456→  metrics?.syncUnknownBlock.resolveAvailabilitySource.inc({source: BlockInputAvailabilitySource.UNKNOWN_SYNC});
   457→
   458→  metrics?.blockInputFetchStats.totalDataPromiseBlockInputsResolvedAvailable.inc();
   459→  if (getBlobsUseful) {
   460→    metrics?.blockInputFetchStats.totalDataPromiseBlockInputsAvailableUsingGetBlobs.inc();
   461→    if (networkReqIdentifiers.length === 0) {
   462→      metrics?.blockInputFetchStats.totalDataPromiseBlockInputsAvailableFromGetBlobs.inc();
   463→    }
   464→  }
   465→  if (networkResBlobSidecars.length > 0) {
   466→    metrics?.blockInputFetchStats.totalDataPromiseBlockInputsFinallyAvailableFromNetworkReqResp.inc();
   467→  }
   468→  if (blockTriedBefore) {
   469→    metrics?.blockInputFetchStats.totalDataPromiseBlockInputsRetriedAvailableFromNetwork.inc();
   470→  }
   471→
   472→  return getBlockInput.availableData(config, block, BlockSource.byRoot, blockData);
   473→}
   474→
   475→/**
   476→ * Download more columns for a BlockInput
   477→ * - unavailableBlockInput should have block, but not enough blobs (deneb) or data columns (fulu)
   478→ *
   479→ * This function may return data promise, and consumer should continue with fetching more blobs or columns from other peers
   480→ * see UnknownBlockSync.fetchUnavailableBlockInput()
   481→ */
   482→export async function unavailableBeaconBlobsByRootPostFulu(
   483→  config: ChainForkConfig,
   484→  network: INetwork,
   485→  peerId: PeerIdStr,
   486→  peerClient: string,
   487→  unavailableBlockInput: BlockInput,
   488→  block: SignedBeaconBlock,
   489→  cachedData: NullBlockInput["cachedData"],
   490→  opts: {
   491→    metrics?: Metrics | null;
   492→    executionEngine: IExecutionEngine;
   493→    emitter: ChainEventEmitter;
   494→    logger?: Logger;
   495→  }
   496→): Promise<BlockInput> {
   497→  if (unavailableBlockInput.block !== null && unavailableBlockInput.type !== BlockInputType.dataPromise) {
   498→    return unavailableBlockInput;
   499→  }
   500→
   501→  if (cachedData.fork === ForkName.deneb || cachedData.fork === ForkName.electra) {
   502→    const {blobsCache, resolveAvailability} = cachedData;
   503→
   504→    // resolve missing blobs
   505→    const blobIdentifiers: deneb.BlobIdentifier[] = [];
   506→    const slot = block.message.slot;
   507→    const blockRoot = config.getForkTypes(slot).BeaconBlock.hashTreeRoot(block.message);
   508→
   509→    const blobKzgCommitmentsLen = (block.message.body as deneb.BeaconBlockBody).blobKzgCommitments.length;
   510→    for (let index = 0; index < blobKzgCommitmentsLen; index++) {
   511→      if (blobsCache.has(index) === false) blobIdentifiers.push({blockRoot, index});
   512→    }
   513→
   514→    let allBlobSidecars: deneb.BlobSidecar[];
   515→    if (blobIdentifiers.length > 0) {
   516→      allBlobSidecars = await network.sendBlobSidecarsByRoot(peerId, blobIdentifiers);
   517→    } else {
   518→      allBlobSidecars = [];
   519→    }
   520→
   521→    // add them in cache so that its reflected in all the blockInputs that carry this
   522→    // for e.g. a blockInput that might be awaiting blobs promise fullfillment in
   523→    // verifyBlocksDataAvailability
   524→    for (const blobSidecar of allBlobSidecars) {
   525→      blobsCache.set(blobSidecar.index, blobSidecar);
   526→    }
   527→
   528→    // check and see if all blobs are now available and in that case resolve availability
   529→    // if not this will error and the leftover blobs will be tried from another peer
   530→    const allBlobs = getBlockInputBlobs(blobsCache);
   531→    const {blobs} = allBlobs;
   532→    if (blobs.length !== blobKzgCommitmentsLen) {
   533→      throw Error(`Not all blobs fetched missingBlobs=${blobKzgCommitmentsLen - blobs.length}`);
   534→    }
   535→    const blockData = {fork: cachedData.fork, ...allBlobs, blobsSource: BlobsSource.byRoot} as BlockInputBlobs;
   536→    resolveAvailability(blockData);
   537→    opts.metrics?.syncUnknownBlock.resolveAvailabilitySource.inc({source: BlockInputAvailabilitySource.UNKNOWN_SYNC});
   538→    return getBlockInput.availableData(config, block, BlockSource.byRoot, blockData);
   539→  }
   540→
   541→  // fulu fork
   542→  const {dataColumnsCache, resolveAvailability} = cachedData as CachedDataColumns;
   543→
   544→  // resolve missing blobs
   545→  const slot = block.message.slot;
   546→  const blockRoot = config.getForkTypes(slot).BeaconBlock.hashTreeRoot(block.message);
   547→
   548→  const blobKzgCommitments = (block.message.body as deneb.BeaconBlockBody).blobKzgCommitments;
   549→  if (blobKzgCommitments.length === 0) {
   550→    const blockData = {
   551→      fork: cachedData.fork,
   552→      dataColumns: [],
   553→      dataColumnsBytes: [],
   554→      dataColumnsSource: DataColumnsSource.gossip,
   555→    } as BlockInputDataColumns;
   556→
   557→    resolveAvailability(blockData);
   558→    opts.metrics?.syncUnknownBlock.resolveAvailabilitySource.inc({source: BlockInputAvailabilitySource.UNKNOWN_SYNC});
   559→    return getBlockInput.availableData(config, block, BlockSource.byRoot, blockData);
   560→  }
   561→
   562→  const sampledColumns = network.custodyConfig.sampledColumns;
   563→  let neededColumns = sampledColumns.reduce((acc, elem) => {
   564→    if (dataColumnsCache.get(elem) === undefined) {
   565→      acc.push(elem);
   566→    }
   567→    return acc;
   568→  }, [] as number[]);
   569→
   570→  let resolveBlockInput: ((block: BlockInput) => void) | null = null;
   571→  const blockInputPromise = new Promise<BlockInput>((resolveCB) => {
   572→    resolveBlockInput = resolveCB;
   573→  });
   574→  if (resolveBlockInput === null) {
   575→    throw Error("Promise Constructor was not executed immediately");
   576→  }
   577→
   578→  const gotColumnsFromExecution = await getDataColumnsFromExecution(
   579→    config,
   580→    network.custodyConfig,
   581→    opts.executionEngine,
   582→    opts.emitter,
   583→    {
   584→      fork: config.getForkName(block.message.slot),
   585→      block: block,
   586→      cachedData: cachedData,
   587→      blockInputPromise,
   588→      resolveBlockInput,
   589→    },
   590→    opts.metrics ?? null
   591→  );
   592→
   593→  if (!gotColumnsFromExecution) {
   594→    const {custodyGroups: peerColumns} = network.getConnectedPeerSyncMeta(peerId);
   595→
   596→    // get match
   597→    const columns = peerColumns.reduce((acc, elem) => {
   598→      if (neededColumns.includes(elem)) {
   599→        acc.push(elem);
   600→      }
   601→      return acc;
   602→    }, [] as number[]);
   603→
   604→    // this peer can't help fetching columns for this block
   605→    if (unavailableBlockInput.block !== null && columns.length === 0 && neededColumns.length > 0) {
   606→      return unavailableBlockInput;
   607→    }
   608→
   609→    let allDataColumnSidecars: fulu.DataColumnSidecar[];
   610→    if (columns.length > 0) {
   611→      allDataColumnSidecars = await network.sendDataColumnSidecarsByRoot(peerId, [{blockRoot, columns}]);
   612→      opts.metrics?.dataColumns.bySource.inc({source: DataColumnsSource.byRoot}, allDataColumnSidecars.length);
   613→    } else {
   614→      allDataColumnSidecars = [];
   615→    }
   616→
   617→    const logCtx = {
   618→      slot: block.message.slot,
   619→      requestedColumns: columns.join(","),
   620→      respondedColumns: allDataColumnSidecars.map((dcs) => dcs.index).join(","),
   621→      peerClient,
   622→    };
   623→
   624→    opts.logger?.verbose("unavailableBeaconBlobsByRootPostFulu: Requested data columns from peer", logCtx);
   625→
   626→    // the same to matchBlockWithDataColumns() without expecting requested data columns = responded data columns
   627→    // because at gossip time peer may not have enough column to return
   628→    for (const dataColumnSidecar of allDataColumnSidecars) {
   629→      dataColumnsCache.set(dataColumnSidecar.index, {
   630→        dataColumn: dataColumnSidecar,
   631→        // TODO: req/resp should return bytes here
   632→        dataColumnBytes: null,
   633→      });
   634→    }
   635→  }
   636→
   637→  // reevaluate needeColumns and resolve availability if possible
   638→  neededColumns = sampledColumns.reduce((acc, elem) => {
   639→    if (dataColumnsCache.get(elem) === undefined) {
   640→      acc.push(elem);
   641→    }
   642→    return acc;
   643→  }, [] as number[]);
   644→
   645→  const logCtx = {
   646→    slot: block.message.slot,
   647→    neededColumns: neededColumns.join(","),
   648→    sampledColumns: sampledColumns.join(","),
   649→  };
   650→
   651→  if (neededColumns.length === 0) {
   652→    const {dataColumns, dataColumnsBytes} = getBlockInputDataColumns(
   653→      (cachedData as CachedDataColumns).dataColumnsCache,
   654→      sampledColumns
   655→    );
   656→
   657→    // don't forget to resolve availability as the block may be stuck in availability wait
   658→    const blockData = {
   659→      fork: config.getForkName(block.message.slot),
   660→      dataColumns,
   661→      dataColumnsBytes,
   662→      dataColumnsSource: DataColumnsSource.byRoot,
   663→    } as BlockInputDataColumns;
   664→    resolveAvailability(blockData);
   665→    opts.logger?.verbose(
   666→      "unavailableBeaconBlobsByRootPostFulu: Resolved availability for block with all data columns",
   667→      logCtx
   668→    );
   669→    return getBlockInput.availableData(config, block, BlockSource.byRoot, blockData);
   670→  }
   671→  opts.logger?.verbose("unavailableBeaconBlobsByRootPostFulu: Still missing data columns for block", logCtx);
   672→  return getBlockInput.dataPromise(config, block, BlockSource.byRoot, cachedData);
   673→}
