     1→import {ChainForkConfig} from "@lodestar/config";
     2→import {ForkSeq} from "@lodestar/params";
     3→import {Epoch, RootHex, phase0} from "@lodestar/types";
     4→import {LodestarError} from "@lodestar/utils";
     5→import {BlockInput} from "../../chain/blocks/types.js";
     6→import {BlockError, BlockErrorCode} from "../../chain/errors/index.js";
     7→import {PartialDownload} from "../../network/reqresp/beaconBlocksMaybeBlobsByRange.js";
     8→import {PeerIdStr} from "../../util/peerId.js";
     9→import {MAX_BATCH_DOWNLOAD_ATTEMPTS, MAX_BATCH_PROCESSING_ATTEMPTS} from "../constants.js";
    10→import {getBatchSlotRange, hashBlocks} from "./utils/index.js";
    11→
    12→/**
    13→ * Current state of a batch
    14→ */
    15→export enum BatchStatus {
    16→  /** The batch has failed either downloading or processing, but can be requested again. */
    17→  AwaitingDownload = "AwaitingDownload",
    18→  /** The batch is being downloaded. */
    19→  Downloading = "Downloading",
    20→  /** The batch has been completely downloaded and is ready for processing. */
    21→  AwaitingProcessing = "AwaitingProcessing",
    22→  /** The batch is being processed. */
    23→  Processing = "Processing",
    24→  /**
    25→   * The batch was successfully processed and is waiting to be validated.
    26→   *
    27→   * It is not sufficient to process a batch successfully to consider it correct. This is
    28→   * because batches could be erroneously empty, or incomplete. Therefore, a batch is considered
    29→   * valid, only if the next sequential batch imports at least a block.
    30→   */
    31→  AwaitingValidation = "AwaitingValidation",
    32→}
    33→
    34→export type Attempt = {
    35→  /** The peer that made the attempt */
    36→  peer: PeerIdStr;
    37→  /** The hash of the blocks of the attempt */
    38→  hash: RootHex;
    39→};
    40→
    41→export type BatchState =
    42→  | {status: BatchStatus.AwaitingDownload; partialDownload: PartialDownload}
    43→  | {status: BatchStatus.Downloading; peer: PeerIdStr; partialDownload: PartialDownload}
    44→  | {status: BatchStatus.AwaitingProcessing; peer: PeerIdStr; blocks: BlockInput[]}
    45→  | {status: BatchStatus.Processing; attempt: Attempt}
    46→  | {status: BatchStatus.AwaitingValidation; attempt: Attempt};
    47→
    48→export type BatchMetadata = {
    49→  startEpoch: Epoch;
    50→  status: BatchStatus;
    51→};
    52→
    53→export type DownloadSuccessOutput =
    54→  | {
    55→      status: BatchStatus.AwaitingProcessing;
    56→      blocks: BlockInput[];
    57→    }
    58→  | {
    59→      status: BatchStatus.AwaitingDownload;
    60→      pendingDataColumns: number[];
    61→    };
    62→
    63→/**
    64→ * Batches are downloaded at the first block of the epoch.
    65→ *
    66→ * For example:
    67→ *
    68→ * Epoch boundary |                                   |
    69→ *  ... | 30 | 31 | 32 | 33 | 34 | ... | 61 | 62 | 63 | 64 | 65 |
    70→ *     Batch 1    |              Batch 2              |  Batch 3
    71→ *
    72→ * Jul2022: Offset changed from 1 to 0, see rationale in {@link BATCH_SLOT_OFFSET}
    73→ */
    74→export class Batch {
    75→  readonly startEpoch: Epoch;
    76→  /** State of the batch. */
    77→  state: BatchState = {status: BatchStatus.AwaitingDownload, partialDownload: null};
    78→  /** BeaconBlocksByRangeRequest */
    79→  readonly request: phase0.BeaconBlocksByRangeRequest;
    80→  /** The `Attempts` that have been made and failed to send us this batch. */
    81→  readonly failedProcessingAttempts: Attempt[] = [];
    82→  /** The `Attempts` that have been made and failed because of execution malfunction. */
    83→  readonly executionErrorAttempts: Attempt[] = [];
    84→  /** The number of download retries this batch has undergone due to a failed request. */
    85→  private readonly failedDownloadAttempts: PeerIdStr[] = [];
    86→  private readonly config: ChainForkConfig;
    87→
    88→  constructor(startEpoch: Epoch, config: ChainForkConfig) {
    89→    const {startSlot, count} = getBatchSlotRange(startEpoch);
    90→
    91→    this.config = config;
    92→    this.startEpoch = startEpoch;
    93→    this.request = {
    94→      startSlot,
    95→      count,
    96→      step: 1,
    97→    };
    98→  }
    99→
   100→  /**
   101→   * Gives a list of peers from which this batch has had a failed download or processing attempt.
   102→   */
   103→  getFailedPeers(): PeerIdStr[] {
   104→    return [...this.failedDownloadAttempts, ...this.failedProcessingAttempts.map((a) => a.peer)];
   105→  }
   106→
   107→  getMetadata(): BatchMetadata {
   108→    return {startEpoch: this.startEpoch, status: this.state.status};
   109→  }
   110→
   111→  /**
   112→   * AwaitingDownload -> Downloading
   113→   */
   114→  startDownloading(peer: PeerIdStr): PartialDownload {
   115→    if (this.state.status !== BatchStatus.AwaitingDownload) {
   116→      throw new BatchError(this.wrongStatusErrorType(BatchStatus.AwaitingDownload));
