const blockInputs: BlockInput[] = [];
// NOTE: head chain can advance between retries, and peers may include sidecars for blocks
// not present in `allBlocks` (e.g., a newer head). Matching by slot breaks in that case.
// Instead, match by block header root and only treat sidecars as "unmatched" if they refer
// to a block header root we did not request.
const lastMatchedSlot = -1;
const neededColumns = prevPartialDownload?.pendingDataColumns ?? sampledColumns;
const shouldHaveAllData = neededColumns.reduce((acc, elem) => acc && requestedColumns.includes(elem), true);

// Group sidecars by block header root so we can match regardless of ordering and avoid
// false positives when a peer responds with a more up-to-date head.
const sidecarsByBlockRoot = new Map<string, fulu.DataColumnSidecar[]>();
for (const sidecar of allDataColumnSidecars) {
  const rootHex = Buffer.from(sidecar.signedBlockHeader.message.bodyRoot).toString("hex");
  const arr = sidecarsByBlockRoot.get(rootHex);
  if (arr) arr.push(sidecar);
  else sidecarsByBlockRoot.set(rootHex, [sidecar]);
}
const requestedBlockRoots = new Set<string>();
for (const block of allBlocks) {
  // Block header root is used to match against sidecar.signedBlockHeader
  const headerRoot = Buffer.from(config.getForkTypes(block.data.message.slot).BeaconBlockHeader.hashTreeRoot(block.data.message)).toString("hex");
  requestedBlockRoots.add(headerRoot);
}

