// Any remaining sidecars that match requested block roots would indicate duplicate / inconsistent response.
// Sidecars for *other* (more up-to-date) blocks may be included during head sync retries; ignore those.
const remainingForRequested: fulu.DataColumnSidecar[] = [];
for (const [rootHex, sidecars] of sidecarsByBlockRoot.entries()) {
  if (requestedBlockRoots.has(rootHex)) {
    remainingForRequested.push(...sidecars);
  }
}

if (remainingForRequested.length > 0) {
  network.reportPeer(peerId, PeerAction.LowToleranceError, "Unmatched dataColumnSidecars");
  throw Error(
    `Unmatched dataColumnSidecars, blocks=${allBlocks.length}, blobs=${
      allDataColumnSidecars.length
    } lastMatchedSlot=${lastMatchedSlot}, pending dataColumnSidecars slots=${remainingForRequested
      .map((blb) => blb.signedBlockHeader.message.slot)
      .join(" ")}`
  );
}

