import {ForkName} from "@lodestar/params";
import {ssz} from "@lodestar/types";
import {describe, expect, it} from "vitest";

import {BlockSource} from "../../../../src/chain/blocks/types.js";
import {DataColumnsSource} from "../../../../src/network/reqresp/types.js";
import {matchBlockWithDataColumns} from "../../../../src/network/reqresp/beaconBlocksMaybeBlobsByRange.js";
import {getConfig} from "../../../utils/config.js";
import {validPeerIdStr} from "../../../utils/peer.js";

// Minimal INetwork stub for matchBlockWithDataColumns
const networkStub = {
  reportPeer: () => {
    // no-op
  },
} as any;

describe("beacon-node / network / reqresp / matchBlockWithDataColumns", () => {
  it("should ignore extra dataColumnSidecars for a newer head block not in allBlocks", () => {
    const config = getConfig(ForkName.fulu, 0);

    // Create 2 consecutive fulu blocks
    const block1 = ssz.fulu.SignedBeaconBlock.defaultValue();
    block1.message.slot = 1;
    (block1.message.body as any).blobKzgCommitments = [new Uint8Array(48)];

    const block2 = ssz.fulu.SignedBeaconBlock.defaultValue();
    block2.message.slot = 2;
    (block2.message.body as any).blobKzgCommitments = [new Uint8Array(48)];

    const headerRoot1 = config.getForkTypes(1).BeaconBlockHeader.hashTreeRoot(block1.message);
    const headerRoot2 = config.getForkTypes(2).BeaconBlockHeader.hashTreeRoot(block2.message);

    // Requested columns for block1 only
    const sampledColumns = [1];
    const requestedColumns = [1];

    const sidecarForBlock1 = ssz.fulu.DataColumnSidecar.defaultValue();
    sidecarForBlock1.index = 1;
    sidecarForBlock1.signedBlockHeader.message.slot = 1;
    sidecarForBlock1.signedBlockHeader.message.bodyRoot = headerRoot1;

    // Extra sidecar: for a newer head block (slot 2), not present in allBlocks
    const sidecarForBlock2 = ssz.fulu.DataColumnSidecar.defaultValue();
    sidecarForBlock2.index = 1;
    sidecarForBlock2.signedBlockHeader.message.slot = 2;
    sidecarForBlock2.signedBlockHeader.message.bodyRoot = headerRoot2;

    // Old code matched by slot and would throw Unmatched dataColumnSidecars.
    expect(() =>
      matchBlockWithDataColumns(
        networkStub,
        validPeerIdStr,
        config,
        sampledColumns,
        requestedColumns,
        [{data: block1}],
        [sidecarForBlock1, sidecarForBlock2] as any,
        1,
        BlockSource.byRange,
        DataColumnsSource.byRange,
        null,
        "Prysm",
        null
      )
    ).not.toThrow();
  });
});

